import React from "react"
import Layout from "../components/Layout"
import BundleCard from "../components/BundleCard"
import DealCard from "../components/DealCard"
import dealsData from "../../data/deals.json"
import bundlesData from "../../data/bundles.json"
import { Link } from "gatsby"

const IndexPage = () => {
  const { deals } = dealsData
  const { bundles } = bundlesData
  const categories = [...new Set(bundles.map(b => b.category))]
  const monthlyEquiv = (d) => {
    if (d.price.monthly) return d.price.monthly
    if (d.price.hourly) return d.price.hourly * 730
    if (d.price.monthlyPerGB) return d.price.monthlyPerGB * 10
    if (d.price.inputPer1M) return d.price.inputPer1M * 5
    if (d.price.annual) return d.price.annual / 12
    return 99999
  }

  const featuredDeals = [...deals]
    .sort((a, b) => monthlyEquiv(a) - monthlyEquiv(b))
    .slice(0, 6)

  return (
    <Layout activeNav="home">
      {/* Hero */}
      <section className="hero">
        <h1>Resource Bundles for Solo Devs</h1>
        <p>
          Curated combinations of VPS, GPU, domains, storage &amp; AI APIs — with real verified pricing and step-by-step setup guides.
        </p>
        <div className="hero-chips">
          {categories.map(cat => (
            <span key={cat} className="hero-chip">{cat.replace("-", " ")}</span>
          ))}
        </div>
        <div className="hero-search">
          <span className="hero-search-icon">🔍</span>
          <input
            type="text"
            placeholder="Search deals, providers, bundles..."
            onKeyUp={e => {
              if (e.key === "Enter" && e.target.value.trim()) {
                window.location.href = `/deals/?q=${encodeURIComponent(e.target.value.trim())}`
              }
            }}
          />
        </div>
      </section>

      {/* Bundles */}
      <section className="section">
        <h2 className="section-title">📦 Workload Bundles</h2>
        <div className="bundle-grid">
          {bundles.map(b => (
            <Link to={`/bundle/${b.slug}`} style={{ textDecoration: "none", color: "inherit" }}>
              <BundleCard key={b.id} bundle={b} deals={deals} />
            </Link>
          ))}
        </div>
      </section>

      {/* Featured Deals */}
      <section className="section">
        <h2 className="section-title">💰 Top Budget Deals</h2>
        <div className="deal-grid">
          {featuredDeals.map(d => (
            <DealCard key={d.id} deal={d} />
          ))}
        </div>
      </section>

      {/* Stats */}
      <section className="stats-grid">
        <div className="stat-card">
          <div className="stat-value">{deals.length}</div>
          <div className="stat-label">Deals Tracked</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{bundles.length}</div>
          <div className="stat-label">Bundles</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{[...new Set(deals.map(d => d.provider))].length}</div>
          <div className="stat-label">Providers</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{[...new Set(deals.map(d => d.category))].length}</div>
          <div className="stat-label">Categories</div>
        </div>
      </section>
    </Layout>
  )
}

export const Head = () => (
  <>
    <title>DevBundles — Resource Deals for Solo Developers</title>
    <meta name="description" content="Curated workload bundles — the best deals on VPS, GPU, domains, storage, and AI APIs for indie developers." />
  </>
)

export default IndexPage
