import React from "react"

const monthlyEquiv = (deal) => {
  if (deal.price.monthly) return deal.price.monthly
  if (deal.price.hourly) return deal.price.hourly * 730
  if (deal.price.monthlyPerGB) return deal.price.monthlyPerGB * 10
  if (deal.price.inputPer1M) return deal.price.inputPer1M * 5
  if (deal.price.annual) return deal.price.annual / 12
  if (deal.price.annualPrice) return deal.price.annualPrice / 12
  return 0
}

export const formatPrice = (deal) => {
  if (deal.price.monthly) return `$${deal.price.monthly}/mo`
  if (deal.price.hourly) return `$${deal.price.hourly}/hr`
  if (deal.price.monthlyPerGB) return `$${deal.price.monthlyPerGB}/GB`
  if (deal.price.inputPer1M) return `$${deal.price.inputPer1M}/1M`
  if (deal.price.annual) return `$${deal.price.annual}/yr`
  if (deal.price.annualPrice) return `$${deal.price.annualPrice}/yr`
  return "—"
}

const BundleCard = ({ bundle, deals }) => {
  const getCheapestDeal = (dealIds) => {
    const matched = dealIds.map(id => deals.find(d => d.id === id)).filter(Boolean)
    if (!matched.length) return null
    return matched.sort((a, b) => monthlyEquiv(a) - monthlyEquiv(b))[0]
  }

  // Compute exact cheapest total
  const requiredTotal = bundle.resources
    .filter(r => r.required)
    .reduce((sum, r) => {
      const cheapest = getCheapestDeal(r.dealIds)
      return sum + (cheapest ? monthlyEquiv(cheapest) : 0)
    }, 0)

  const withOptional = bundle.resources
    .reduce((sum, r) => {
      const cheapest = getCheapestDeal(r.dealIds)
      return sum + (cheapest ? monthlyEquiv(cheapest) : 0)
    }, 0)

  const categoryColors = { "ai-infra": "#8b5cf6", "web-infra": "#10b981" }

  return (
    <article className="bundle-card">
      <div className="bundle-card-header">
        <span className="bundle-card-icon">{bundle.icon}</span>
        <span className="bundle-card-category" style={{
          background: categoryColors[bundle.category] || "#444", color: "#fff",
        }}>
          {bundle.category.replace("-", " ")}
        </span>
      </div>
      <h3 className="bundle-card-name">{bundle.name}</h3>
      <p className="bundle-card-desc">{bundle.description}</p>

      <div>
        {bundle.resources.map((r, i) => {
          const cheapest = getCheapestDeal(r.dealIds)
          return (
            <div key={i} className="bundle-card-resource">
              <span className="bundle-card-resource-label">
                {r.label} {!r.required && <span className="bundle-card-resource-optional">(optional)</span>}
              </span>
              <span className={`bundle-card-resource-price ${!cheapest ? "empty" : ""}`}>
                {cheapest ? formatPrice(cheapest) : "—"}
              </span>
            </div>
          )
        })}
      </div>

      {/* Exact price instead of range */}
      <div className="bundle-card-footer">
        <span className="bundle-card-range-label">
          {bundle.estimatedCostRange.period === "annual" ? "/year" : "/month"}
        </span>
        <div style={{ textAlign: "right" }}>
          <span className="bundle-card-range-value">
            ${requiredTotal.toFixed(2)}
          </span>
          {withOptional > requiredTotal && (
            <div style={{ fontSize: "0.65rem", color: "var(--text-muted)", fontFamily: "var(--font-mono)" }}>
              ${withOptional.toFixed(2)} with optional
            </div>
          )}
        </div>
      </div>

      <div className="bundle-card-meta">
        {bundle.setupSteps.length} setup steps · {bundle.difficulty}
      </div>
    </article>
  )
}

export default BundleCard
